vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 p0 = .2*vec2 (q18,q19);
vec2 uv1 = 12*(vUv-.5 + p0)*uAspect.xy;

rs.x = atan(uv1.y,uv1.x)/q28+uTime/4;

rs.y = .2/(.1+length(uv1))+uTime/4;

vec3 ret1 = texture(sampler_main, rs);

vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
float dx = GetPixel (rs-hor) - GetPixel (rs+hor);
float dy = GetPixel (rs-ver) - GetPixel (rs+ver);
vec2 dz = vec2 (dx,dy);


rs2.x = atan(uv1.y, uv1.x) ;
rs2.y = .1*q27/(abs(.2*q1)+.1+length(uv1))+uTime +rs.x*sin(uTime/14)*2;

rs2 = .15*cos(rs2*q27*3) - dz*2;;
vec3 dots = clamp01(.01*q26/length(rs2))  ;

ret1 = 1*ret1 +  dots -.1;

ret = 1*ret1;

  fragColor = ret;
}
